module.exports = {
  solarTermsData,
  startYear: 1583,
  endYear: 2135,
  
  /**
   * 获取指定年份的节气数据
   * @param {number} year - 年份
   * @returns {string|null} 压缩的节气数据字符串
   */
  getYearData(year) {
    const index = year - 1583;
    if (index < 0 || index >= solarTermsData.length) {
      return null;
    }
    return solarTermsData[index];
  },
  
  /**
   * 解析节气数据，获取指定节气的分钟数
   * @param {string} yearData - 年度节气数据
   * @param {number} solarTermIndex - 节气索引（0-23）
   * @returns {number} 从年初开始的总分钟数
   */
  parseSolarTerm(yearData, solarTermIndex) {
    if (solarTermIndex < 0 || solarTermIndex > 23) {
      throw new Error(`节气索引超出范围: ${solarTermIndex}`);
    }
    const start = solarTermIndex * 5;
    const hexValue = yearData.substr(start, 5);
    return parseInt(hexValue, 16);
  },
  
  /**
   * 获取节气名称
   * @param {number} index - 节气索引（0-23）
   * @returns {string} 节气名称
   */
  getSolarTermName(index) {
    const names = [
      '小寒', '大寒', '立春', '雨水', '惊蛰', '春分',
      '清明', '谷雨', '立夏', '小满', '芒种', '夏至',
      '小暑', '大暑', '立秋', '处暑', '白露', '秋分',
      '寒露', '霜降', '立冬', '小雪', '大雪', '冬至'
    ];
    return names[index] || '';
  },
  
  /**
   * 获取指定年份指定节气的具体时间
   * @param {number} year - 年份（1583-2135）
   * @param {number|string} solarTerm - 节气索引（0-23）或节气名称
   * @returns {Date|null} 节气时间的Date对象，如果参数无效则返回null
   * 
   * @example
   * // 使用索引
   * const date1 = getSolarTermTime(2000, 0); // 2000年小寒
   * 
   * // 使用节气名称
   * const date2 = getSolarTermTime(2000, '立春'); // 2000年立春
   */
  getSolarTermTime(year, solarTerm) {
    // 验证年份范围
    if (year < 1583 || year > 2135) {
      console.error(`年份超出范围: ${year}，支持范围: 1583-2135`);
      return null;
    }
    
    // 获取节气索引
    let solarTermIndex;
    if (typeof solarTerm === 'number') {
      solarTermIndex = solarTerm;
    } else if (typeof solarTerm === 'string') {
      // 根据节气名称查找索引
      const names = [
        '小寒', '大寒', '立春', '雨水', '惊蛰', '春分',
        '清明', '谷雨', '立夏', '小满', '芒种', '夏至',
        '小暑', '大暑', '立秋', '处暑', '白露', '秋分',
        '寒露', '霜降', '立冬', '小雪', '大雪', '冬至'
      ];
      solarTermIndex = names.indexOf(solarTerm);
      if (solarTermIndex === -1) {
        console.error(`无效的节气名称: ${solarTerm}`);
        return null;
      }
    } else {
      console.error(`无效的节气参数类型: ${typeof solarTerm}`);
      return null;
    }
    
    // 验证节气索引
    if (solarTermIndex < 0 || solarTermIndex > 23) {
      console.error(`节气索引超出范围: ${solarTermIndex}，有效范围: 0-23`);
      return null;
    }
    
    // 获取年度数据
    const yearData = this.getYearData(year);
    if (!yearData) {
      console.error(`无法获取年份数据: ${year}`);
      return null;
    }
    
    // 解析节气分钟数
    const totalMinutes = this.parseSolarTerm(yearData, solarTermIndex);
    
    // 计算具体时间
    const yearStart = new Date(year, 0, 1, 0, 0, 0, 0);
    const solarTermTime = new Date(yearStart.getTime() + totalMinutes * 60 * 1000);
    
    return solarTermTime;
  },
  
  /**
   * 获取指定年份指定节气的格式化时间字符串
   * @param {number} year - 年份（1583-2135）
   * @param {number|string} solarTerm - 节气索引（0-23）或节气名称
   * @param {string} format - 格式化模板，可选值：
   *   - 'full': '2000年1月6日 9时1分'（默认）
   *   - 'iso': '2000-01-06T09:01:00'
   *   - 'short': '2000/01/06 09:01'
   *   - 'chinese': '二〇〇〇年一月六日九时一分'
   * @returns {string|null} 格式化的时间字符串，如果参数无效则返回null
   * 
   * @example
   * const str1 = getSolarTermTimeString(2000, 0); // '2000年1月6日 9时1分'
   * const str2 = getSolarTermTimeString(2000, '立春', 'iso'); // '2000-02-04T20:32:00'
   */
  getSolarTermTimeString(year, solarTerm, format = 'full') {
    const date = this.getSolarTermTime(year, solarTerm);
    if (!date) {
      return null;
    }
    
    const y = date.getFullYear();
    const m = date.getMonth() + 1;
    const d = date.getDate();
    const h = date.getHours();
    const min = date.getMinutes();
    
    switch (format) {
      case 'full':
        return `${y}年${m}月${d}日 ${h}时${min}分`;
      
      case 'iso':
        return `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}T${String(h).padStart(2, '0')}:${String(min).padStart(2, '0')}:00`;
      
      case 'short':
        return `${y}/${String(m).padStart(2, '0')}/${String(d).padStart(2, '0')} ${String(h).padStart(2, '0')}:${String(min).padStart(2, '0')}`;
      
      case 'chinese':
        const chineseNums = ['〇', '一', '二', '三', '四', '五', '六', '七', '八', '九'];
        const toChinese = (num) => String(num).split('').map(n => chineseNums[parseInt(n)]).join('');
        return `${toChinese(y)}年${toChinese(m)}月${toChinese(d)}日${toChinese(h)}时${toChinese(min)}分`;
      
      default:
        return `${y}年${m}月${d}日 ${h}时${min}分`;
    }
  },
  
  /**
   * 获取指定年份所有节气的时间
   * @param {number} year - 年份（1583-2135）
   * @returns {Array<Object>|null} 包含所有节气信息的数组，每个元素包含：
   *   - index: 节气索引
   *   - name: 节气名称
   *   - date: Date对象
   *   - string: 格式化字符串
   * 如果年份无效则返回null
   * 
   * @example
   * const allTerms = getAllSolarTerms(2000);
   * // [
   * //   { index: 0, name: '小寒', date: Date, string: '2000年1月6日 9时1分' },
   * //   { index: 1, name: '大寒', date: Date, string: '2000年1月21日 3时22分' },
   * //   ...
   * // ]
   */
  getAllSolarTerms(year) {
    if (year < 1583 || year > 2135) {
      console.error(`年份超出范围: ${year}，支持范围: 1583-2135`);
      return null;
    }
    
    const yearData = this.getYearData(year);
    if (!yearData) {
      return null;
    }
    
    const results = [];
    for (let i = 0; i < 24; i++) {
      const date = this.getSolarTermTime(year, i);
      results.push({
        index: i,
        name: this.getSolarTermName(i),
        date: date,
        string: this.getSolarTermTimeString(year, i)
      });
    }
    
    return results;
  }
};
